void cxl_destroy_region(struct cxl_region *cxlr)
{
	struct cxl_port *port = cxlrd_to_port(cxlr->cxlrd);

	devm_release_action(port->uport_dev, __unregister_region, cxlr);
}
EXPORT_SYMBOL_NS_GPL(cxl_destroy_region, "CXL");


